#include <bits/stdc++.h>
using namespace std;

int main() {
    string text;
    getline(cin, text);
    string from, to;
    cin >> from >> to;

    stringstream ss(text);
    vector<string> words;
    string word;
    while (ss >> word) {
        if (word == from) word = to;
        words.push_back(word);
    }

    for (int i = 0; i < (int)words.size(); ++i) {
        if (i) cout << " ";
        cout << words[i];
    }
    cout << endl;
    return 0;
}
